	.PROC	M680002	.REF	SM8	.REF	LIB	.REF	DRIVERS	.LOC	0START:	LOAD.W	D0,#45	LOAD.W	D1,#350	LOAD.W	D2,#INVDOT	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#300	LOAD.W	D4,#10	SWAP.W	D4	LOAD.W	D4,#1520$:	CALL	DRTRANCHE	SWAP.W	D4	ADD.W	D4,#10	SWAP.W	D4	ADD.W	D4,#15	COMP.W	D4,#200	JUMP,LO 20$	EXIT;----------\\; DRTRANCHE >;==========/; Dessine une tranche de gteau.; in	D0.W	angle initial (0..360);	D1.W	angle d'paisseur (0..360);	D2.W	mode de dessin;	D3.L	centre (y;x);	D4.W	rayon; out	-; mod	D7.WDRTRANCHE:	PUSHM.L	D0..D6	TSET.L	D2:#BNCTDOT	; D2 <-- pas de rz du traitill	ADD.W	D1,D0		; D1 <-- angle d'arrive	LOAD.L	D6,D3		; D6 <-- position initiale	LOAD.L	D5,#24*(360/6)	; D5 <-- L*(360/2PI)	DIV.WU	D5,D4	TEST.W	D5	JUMP',NE 20$	INC.W	D520$:LOAD.W D5,#6	PUSHM.L	D3..D5	CALL	PCERCLE		; D5 <-- nouveau point	LOAD.L	D3,D6	LOAD.L	D4,D5	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	.W	LIB,?DRSEG	LOAD.L	D6,D3		; D6 <-- position suivante	POPM.L	D3..D5	COMP.W	D0,D1	JUMP',HS 50$	ADD.W	D0,D5		; D0 <-- angle suivant	COMP.W	D0,D1	JUMP,LS 20$	LOAD.W	D0,D1	JUMP	20$50$:	LOAD.L	D4,D3	LOAD.L	D3,D6	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	.W	LIB,?DRSEG	POPM.L	D0..D6	RET;--------\\; PCERCLE >;--------/; Calcul les coordonnes d'un point situ sur un cercle.; in	D0.W	angle;	D3.L	centre (y;x);	D4.W	rayon; out	D5.L	point (y;x); mod	D5.L, D7.WPCERCLE:	PUSH.L	D1	CALL	SINUS	SWAP.W	D4	MUL.WA	D1,D4	SWAP.W	D4	ADD.L	D1,#10000/2	DIV.WA	D1,#10000	SWAP.W	D3	ADD.W	D1,D3	SWAP.W	D3	LOAD.W	D5,D1	SWAP.W	D5	CALL	COSINUS	MUL.WA	D1,D4	ADD.L	D1,#10000/2	DIV.WA	D1,#10000	ADD.W	D1,D3	LOAD.W	D5,D1	POP.L	D1	RET;--------\\; COSINUS >;--------/; Calcul rapidement un cosinus.; in	D0.W	angle (0..360); out	D1.W	cosinus (-10000..+10000); mod	D1.L, D7.WCOSINUS:	PUSH.L	D0	SUB.W	D0,#90	NEG.W	D0	JUMP',NC 50$	ADD.W	D0,#36050$:	CALL	SINUS	POP.L	D0	RET;--------\\; SINUS   >;--------/; Calcul rapidement un sinus.; in	D0.W	angle (0..360); out	D1.W	sinus (-10000..+10000); mod	D1.L, D7.WSINUS:	PUSHM.L	D0,A3	LOAD.L	A3,#R16"TSINUS	AND.L	D0,#H'FFFF	DIV.WU	D0,#360	SWAP.W	D0		; D0 <-- 0..360-1	COMP.W	D0,#90	JUMP',LS 40$	COMP.W	D0,#180	JUMP',LS 30$	COMP.W	D0,#270	JUMP',LS 20$				; angle 270..360 =>	SUB.W	D0,#360	NEG.W	D0	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	NEG.W	D1	JUMP'	90$20$:				; angle 180..270 =>	SUB.W	D0,#180	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	NEG.W	D1	JUMP'	90$30$:				; angle 90..180 =>	SUB.W	D0,#180	NEG.W	D0	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	JUMP'	90$40$:				; angle 0..90 =>	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W);	JUMP'	90$90$:	POPM.L	D0,A3	RETTSINUS:	.W	0,175,349,523,698,872,1045,1219,1392,1564	.W	1736,1908,2079,2250,2419,2588,2756,2924,3090,3256	.W	3420,3584,3746,3907,4067,4226,4384,4540,4795,4848	.W	5000,5150,5299,5446,5592,5736,5878,6018,6157,6293	.W	6428,6561,6691,6820,6947,7071,7193,7314,7431,7547	.W	7660,7771,7880,7986,8090,8192,8290,8387,8480,8572	.W	8660,8746,8829,8910,8988,9063,9135,9205,9272,9336	.W	9397,9455,9511,9563,9613,9659,9703,9744,9781,9816	.W	9848,9877,9903,9925,9945,9962,9976,9986,9994,9998	.W	10000	.END	START